import argparse, json
from pathlib import Path
import torch
from torch import nn

try:
    from tabular import featurize_dict as featurize_dict_v1, FEATURE_DIM as FEATURE_DIM_V1, TabularMLP as TabularMLP_V1
except Exception:
    featurize_dict_v1 = None; FEATURE_DIM_V1 = None; TabularMLP_V1 = None
try:
    from tabular_v2 import featurize_dict as featurize_dict_v2, FEATURE_DIM as FEATURE_DIM_V2, TabularMLP as TabularMLP_V2
except Exception:
    featurize_dict_v2 = None; FEATURE_DIM_V2 = None; TabularMLP_V2 = None


def load_data(data_path):
    return torch.load(Path(data_path) / 'test.pt', map_location='cpu', weights_only=False)


def pred_prior(ckpt, data, device):
    n = len(data['node_features'])
    p = ckpt.get('probs', ckpt.get('prior', None))
    if p is None:
        p = torch.full((128,), 0.02)
    return p.float().view(1, -1).repeat(n, 1)


def _pred_tabular_common(ckpt, X, cls, default_dim):
    device = torch.device('cuda' if torch.cuda.is_available() else 'cpu')
    mean = ckpt.get('mean', torch.zeros(X.size(1)))
    std = ckpt.get('std', torch.ones(X.size(1))).clamp_min(1e-4)
    Xn = ((X - mean) / std).float().to(device)
    hidden = ckpt.get('hidden', ckpt.get('hidden_dim', 512))
    layers = ckpt.get('layers', 3)
    dropout = ckpt.get('dropout', 0.0)
    try:
        model = cls(ckpt.get('feature_dim', default_dim), hidden, layers, dropout).to(device)
    except TypeError:
        model = cls(in_dim=ckpt.get('feature_dim', default_dim), hidden=hidden, layers=layers, dropout=dropout).to(device)
    state = ckpt.get('model_state', ckpt.get('state_dict'))
    model.load_state_dict(state)
    model.eval()
    outs = []
    with torch.no_grad():
        for s in range(0, Xn.size(0), 4096):
            outs.append(torch.sigmoid(model(Xn[s:s+4096])).cpu())
    return torch.cat(outs, 0)


def pred_tabular_v1(ckpt, data):
    X = featurize_dict_v1(data)
    return _pred_tabular_common(ckpt, X, TabularMLP_V1, FEATURE_DIM_V1)


def pred_tabular_v2(ckpt, data):
    X = featurize_dict_v2(data)
    return _pred_tabular_common(ckpt, X, TabularMLP_V2, FEATURE_DIM_V2)


def pred_any(checkpoint, data):
    ckpt = torch.load(checkpoint, map_location='cpu', weights_only=False)
    typ = ckpt.get('type', '')
    if typ in ('prior', 'constant') or 'probs' in ckpt or 'prior' in ckpt:
        return pred_prior(ckpt, data, torch.device('cpu'))
    if typ == 'tabular_v2':
        return pred_tabular_v2(ckpt, data)
    if typ == 'tabular' or ('model_state' in ckpt and featurize_dict_v1 is not None):
        return pred_tabular_v1(ckpt, data)
    if typ == 'ensemble':
        members = ckpt.get('members', [])
        weights = ckpt.get('weights', None)
        if weights is None:
            weights = [1.0 / max(len(members), 1)] * len(members)
        out = None; sw = 0.0
        base = Path(checkpoint).parent
        for m, w in zip(members, weights):
            mp = Path(m)
            if not mp.exists():
                mp = base / m
            p = pred_any(str(mp), data)
            out = p * float(w) if out is None else out + p * float(w)
            sw += float(w)
        return out / max(sw, 1e-12)
    raise ValueError(f'Unsupported checkpoint type: {typ}, keys={list(ckpt.keys())}')


def main():
    ap = argparse.ArgumentParser()
    ap.add_argument('--data_path', required=True)
    ap.add_argument('--checkpoint', required=True)
    ap.add_argument('--output', required=True)
    args = ap.parse_args()
    data = load_data(args.data_path)
    pred = pred_any(args.checkpoint, data).clamp(0.0, 1.0).tolist()
    with open(args.output, 'w') as f:
        json.dump({'predictions': pred}, f)

if __name__ == '__main__':
    main()
